def list_floating_labels(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch schematic file")],
) -> dict[str, Any]:
    """Returns all net labels in the schematic that are not connected to any component pin. A label is 'floating' when no component pin falls on the wire-network reachable from the label's position. Floating labels indicate misplaced or off-grid labels that cause ERC errors. Does not require the KiCAD UI to be running."""
    return dispatch_command("list_floating_labels", {"schematicPath": schematicPath})


def list_schematic_components(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    filter: Annotated[Optional[ListSchematicComponentsFilter], Field(description="Optional filters")] = None,
) -> dict[str, Any]:
    """List all components in a schematic with their references, values, positions, and pins. Essential for inspecting what's on the schematic before making edits."""
    return dispatch_command("list_schematic_components", {"schematicPath": schematicPath, "filter": filter})


def list_schematic_labels(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    netName: Annotated[Optional[str], Field(description="Filter to labels whose name exactly matches this string (case-sensitive). Omit to return all labels.")] = None,
    labelType: Annotated[Optional[Literal["net", "global", "power"]], Field(description="Filter by label type. 'net' = local label, 'global' = global label, 'power' = power symbol. Omit to return all types.")] = None,
) -> dict[str, Any]:
    """List all net labels, global labels, and power flags in the schematic. Optionally filter by label name (netName) and/or label type (labelType)."""
    return dispatch_command("list_schematic_labels", {"schematicPath": schematicPath, "netName": netName, "labelType": labelType})


def list_schematic_nets(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
) -> dict[str, Any]:
    """List all nets in the schematic with their connections."""
    return dispatch_command("list_schematic_nets", {"schematicPath": schematicPath})


def list_schematic_texts(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    text: Annotated[Optional[str], Field(description="Case-insensitive substring filter \u2014 only return texts containing this string")] = None,
) -> dict[str, Any]:
    """List all free-form text annotations (notes, headings, documentation strings) in the schematic. Returns position, angle, font size, bold/italic flags, and justification for each text element. Optionally filter by a substring match on the text content."""
    return dispatch_command("list_schematic_texts", {"schematicPath": schematicPath, "text": text})


def list_schematic_wires(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
) -> dict[str, Any]:
    """List all wires in the schematic with start/end coordinates."""
    return dispatch_command("list_schematic_wires", {"schematicPath": schematicPath})


def move_schematic_component(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    reference: Annotated[str, Field(description="Reference designator (e.g., R1, U1)")],
    position: Annotated[MoveSchematicComponentPosition, Field(description="New position in schematic mm coordinates")],
    preserveWires: Annotated[Optional[bool], Field(description="Stretch connected wire endpoints to follow the move (default true)")] = None,
) -> dict[str, Any]:
    """Move a placed symbol to a new position in the schematic. By default (preserveWires=true) wire endpoints touching the component's pins are stretched to follow the new position."""
    return dispatch_command("move_schematic_component", {"schematicPath": schematicPath, "reference": reference, "position": position, "preserveWires": preserveWires})


def move_schematic_net_label(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    netName: Annotated[str, Field(description="Name of the net label to move")],
    newPosition: Annotated[MoveSchematicNetLabelNewposition, Field(description="Target position in mm")],
    currentPosition: Annotated[Optional[MoveSchematicNetLabelCurrentposition], Field(description="Current position to disambiguate when multiple labels share the same name")] = None,
    labelType: Annotated[Optional[Literal["label", "global_label", "hierarchical_label"]], Field(description="Restrict search to a specific label type")] = None,
) -> dict[str, Any]:
    """Move a net label (local, global, or hierarchical) to a new position in the schematic. Use currentPosition to disambiguate when multiple labels share the same name."""
    return dispatch_command("move_schematic_net_label", {"schematicPath": schematicPath, "netName": netName, "newPosition": newPosition, "currentPosition": currentPosition, "labelType": labelType})


def remove_schematic_component_property(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    reference: Annotated[str, Field(description="Reference designator of the component (e.g. R1, U3)")],
    name: Annotated[str, Field(description="Custom property name to remove (e.g. 'MPN', 'Distributor_PN', 'OldField')")],
) -> dict[str, Any]:
    """Remove a single custom property from a placed schematic symbol.

Built-in fields (Reference, Value, Footprint, Datasheet) cannot be removed —
KiCad requires them on every symbol. To clear a built-in field, use
edit_schematic_component and set its value to an empty string."""
    return dispatch_command("remove_schematic_component_property", {"schematicPath": schematicPath, "reference": reference, "name": name})


def rotate_schematic_component(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    reference: Annotated[str, Field(description="Reference designator (e.g., R1, U1)")],
    angle: Annotated[float, Field(description="Absolute rotation in degrees (0, 90, 180, 270). This is the symbol's final orientation, not a relative increment \u2014 passing 90 sets the symbol to 90\u00b0 regardless of its current angle (unlike KiCad's UI 'R' key).")],
    mirror: Annotated[Optional[Literal["x", "y"]], Field(description="Optional mirror axis")] = None,
) -> dict[str, Any]:
    """Rotate a placed symbol in the schematic."""
    return dispatch_command("rotate_schematic_component", {"schematicPath": schematicPath, "reference": reference, "angle": angle, "mirror": mirror})


def run_erc(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch schematic file")],
) -> dict[str, Any]:
    """Runs the KiCAD Electrical Rules Check (ERC) on a schematic and returns all violations. Use after wiring to verify the schematic before generating a netlist."""
    return dispatch_command("run_erc", {"schematicPath": schematicPath})


def set_schematic_component_property(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch file")],
    reference: Annotated[str, Field(description="Reference designator of the component (e.g. R1, U3)")],
    name: Annotated[str, Field(description="Property name (e.g. 'MPN', 'Manufacturer', 'DigiKey_PN', 'Voltage', 'Dielectric')")],
    value: Annotated[str, Field(description="Property value to write (use empty string to clear)")],
    x: Annotated[Optional[float], Field(description="Label X position in mm (default: component X)")] = None,
    y: Annotated[Optional[float], Field(description="Label Y position in mm (default: component Y)")] = None,
    angle: Annotated[Optional[float], Field(description="Label rotation in degrees (default: 0)")] = None,
    hide: Annotated[Optional[bool], Field(description="Hide the property text on the schematic canvas. Defaults to true for newly-created custom properties.")] = None,
    fontSize: Annotated[Optional[float], Field(description="Font size in mm for the label (default: 1.27)")] = None,
    justify: Annotated[Optional[str], Field(description="Text justification for the property label. KiCad alignment keywords: \"left\", \"right\", \"center\", \"top\", \"bottom\", or combined e.g. \"left top\". Omit to leave unchanged. Pass \"center\" to reset to the KiCad default.")] = None,
) -> dict[str, Any]:
    """Add or update a single custom property on a placed schematic symbol.

This is a focused convenience wrapper around edit_schematic_component for the very
common case of attaching one BOM / sourcing field at a time. The property is
created if it does not already exist on the component.

Typical custom properties:
  • MPN, Manufacturer, Manufacturer_PN — manufacturer part number metadata
  • DigiKey, DigiKey_PN, Mouser_PN, LCSC, JLCPCB_PN — distributor part numbers
  • Voltage, Tolerance, Power, Dielectric, Temperature_Coefficient — passive parameters
  • Description, Notes — free-form documentation
  • Any custom field your BOM exporter expects.

These properties are written into the .kicad_sch file as standard KiCad property
records, are exported by export_bom, and are picked up by the JLCPCB and Digi-Key
sourcing tools. Newly-created properties default to hidden — set hide=false to
display the value on the schematic canvas.

For batch updates of multiple properties at once, use edit_schematic_component
with the `properties` parameter instead."""
    return dispatch_command("set_schematic_component_property", {"schematicPath": schematicPath, "reference": reference, "name": name, "value": value, "x": x, "y": y, "angle": angle, "hide": hide, "fontSize": fontSize, "justify": justify})


def snap_to_grid(
    schematicPath: Annotated[str, Field(description="Path to the .kicad_sch schematic file")],
    gridSize: Annotated[Optional[float], Field(description="Grid spacing in mm (default: 2.54 \u2014 standard KiCAD schematic grid)")] = None,
    elements: Annotated[Optional[List[Literal["wires", "junctions", "labels", "components"]]], Field(description="Element types to snap (default: [\"wires\", \"junctions\", \"labels\"]). \"components\" is opt-in \u2014 moving a component without re-routing wires creates new mismatches.")] = None,
) -> dict[str, Any]:
    """Snap schematic element coordinates to the nearest grid point. KiCAD uses exact integer matching for connectivity, so off-grid coordinates cause wires that look connected to fail ERC checks. Modifies the .kicad_sch file in place. Does not require the KiCAD UI to be running."""
    return dispatch_command("snap_to_grid", {"schematicPath": schematicPath, "gridSize": gridSize, "elements": elements})


def sync_schematic_to_board(
    schematicPath: Annotated[str, Field(description="Absolute path to the .kicad_sch schematic file")],
    boardPath: Annotated[str, Field(description="Absolute path to the .kicad_pcb board file")],
) -> dict[str, Any]:
    """Import the schematic netlist into the PCB board — equivalent to pressing F8 in KiCAD (Tools → Update PCB from Schematic). MUST be called after the schematic is complete and before placing or routing components on the PCB. Without this step, the board has no footprints and no net assignments — place_component and route_pad_to_pad will produce an empty, unroutable board."""
    return dispatch_command("sync_schematic_to_board", {"schematicPath": schematicPath, "boardPath": boardPath})


